            let value = Self.allCases.first(where: { $0.rawValue == rawValue })
            self = value ?? Self.sdkUnknown(rawValue)
        }

        public var rawValue: Swift.String {
            switch self {
            case .assertionCreated: return "ASSERTION_CREATED"
            case .assertionDeleted: return "ASSERTION_DELETED"
            case .assertionUpdated: return "ASSERTION_UPDATED"
            case .serviceAchievabilityUpdated: return "SERVICE_ACHIEVABILITY_UPDATED"
            case .serviceCreated: return "SERVICE_CREATED"
            case .serviceDeleted: return "SERVICE_DELETED"
            case .serviceFunctionCreated: return "SERVICE_FUNCTION_CREATED"
